package ui.admin;
import javax.swing.*;import javax.swing.table.*;import java.awt.*;import controller.*;import model.*;import util.*;import ui.common.TableStyle;
public class ManageUsersPanel extends JPanel{ JTable table=new JTable(); public ManageUsersPanel(){setBackground(UITheme.BG);setLayout(new BorderLayout());add(UITheme.title("Manage Users"),BorderLayout.NORTH);add(new JScrollPane(table),BorderLayout.CENTER);JPanel p=UITheme.panel();JButton act=UITheme.button("Activate");JButton de=UITheme.button("Deactivate");p.add(act);p.add(de);add(p,BorderLayout.SOUTH);act.addActionListener(e->status(Constants.STATUS_ACTIVE));de.addActionListener(e->status(Constants.STATUS_INACTIVE));load();} void load(){DefaultTableModel m=new DefaultTableModel(new Object[]{"ID","Name","Email","Role","Status"},0); for(User u:new AdminController().users())m.addRow(new Object[]{u.getId(),u.getName(),u.getEmail(),u.getRole(),u.getStatus()});table.setModel(m);TableStyle.apply(table);} void status(String s){int r=table.getSelectedRow();if(r<0)return;new AdminController().userStatus(Integer.parseInt(table.getValueAt(r,0).toString()),s);load();}}
